// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
// The returned emailBody is ready to be converted to []byte and sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Basic validation of email addresses
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid sender address: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid recipient address: %w", err)
	}

	// 2. Prevent Header Injection
	// Remove carriage returns and line feeds from the subject to prevent malicious header manipulation.
	cleanSubject := strings.NewReplacer("\r", "", "\n", "").Replace(subject)

	// 3. Define HTML template for the email body
	// Using html/template automatically escapes user input to prevent XSS.
	const htmlTmpl = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
    .container { max-width: 600px; margin: 20px auto; border: 1px solid #eee; padding: 20px; }
    .label { font-weight: bold; color: #555; }
    .content-box { background-color: #f9f9f9; padding: 15px; border: 1px solid #ddd; margin-top: 10px; white-space: pre-wrap; }
  </style>
</head>
<body>
  <div class="container">
    <h2>User Feedback Received</h2>
    <p><span class="label">Submitted by:</span> {{.UserName}}</p>
    <p><span class="label">Subject:</span> {{.Subject}}</p>
    <div>
      <span class="label">Message:</span><br>
      <div class="content-box">{{.Content}}</div>
    </div>
  </div>
</body>
</html>`

	tmpl, err := template.New("feedback").Parse(htmlTmpl)
	if err != nil {
		return "", fmt.Errorf("failed to parse template: %w", err)
	}

	// 4. Execute template with user data
	var bodyBuf bytes.Buffer
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
	}

	if err := tmpl.Execute(&bodyBuf, data); err != nil {
		return "", fmt.Errorf("failed to execute template: %w", err)
	}

	// 5. Construct RFC 5322 Headers
	// Headers and Body must be separated by a double CRLF (\r\n\r\n).
	header := fmt.Sprintf("From: %s\r\n"+
		"To: %s\r\n"+
		"Subject: Feedback: %s\r\n"+
		"MIME-Version: 1.0\r\n"+
		"Content-Type: text/html; charset=UTF-8\r\n"+
		"\r\n",
		fromAddr, toAddr, cleanSubject)

	return header + bodyBuf.String(), nil
}

func main() {
	// Example usage:
	from := "system@example.com"
	to := "support@example.com"
	user := "John Doe"
	sub := "Issue with Login"
	content := "Hello, I cannot login to my account. It says 'Invalid Credentials' even though they are correct."

	email, err := BuildFeedbackEmail(from, to, user, sub, content)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Generated Email Content:")
	fmt.Println(email)

	// To send via net/smtp:
	// auth := smtp.PlainAuth("", "user", "pass", "smtp.example.com")
	// err = smtp.SendMail("smtp.example.com:587", auth, from, []string{to}, []byte(email))
}

