package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
// The returned emailBody includes headers and the body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation: Ensure addresses are not empty
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate and parse email addresses.
	// mail.ParseAddress ensures the format is correct and allows us to use .String() 
	// later to properly quote names and format the address for headers.
	f, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	t, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 1. Prevent Email Header Injection and handle non-ASCII characters.
	// We use mime.QEncoding (RFC 2047) to encode the subject line. This ensures that
	// characters like \r or \n are encoded (e.g., as =0D or =0A), preventing 
	// an attacker from injecting additional headers or terminating the header section.
	encodedSubject := mime.QEncoding.Encode("utf-8", "Feedback: "+subject)

	// 2. Prevent Cross-Site Scripting (XSS) in the HTML body.
	// We escape all user-provided strings before placing them in the HTML template.
	// This ensures that any HTML/JavaScript submitted by the user is rendered as text.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// 3. Construct email headers.
	// We use \r\n (CRLF) as the line terminator per RFC 5322 requirements.
	var sb strings.Builder
	fmt.Fprintf(&sb, "From: %s\r\n", f.String())
	fmt.Fprintf(&sb, "To: %s\r\n", t.String())
	fmt.Fprintf(&sb, "Subject: %s\r\n", encodedSubject)
	sb.WriteString("MIME-Version: 1.0\r\n")
	sb.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	sb.WriteString("\r\n") // End of headers

	// 4. Construct HTML body.
	// The <pre> tag is used for feedback content to preserve user formatting (newlines/spaces)
	// while the content itself is safely escaped.
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body style="font-family: sans-serif;">
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeContent,
	)

	sb.WriteString(htmlBody)

	return sb.String(), nil
}

func main() {
	// Example usage:
	// The generated string can be converted to []byte and passed to smtp.SendMail.
	userName := "John <Doe>"
	subject := "Urgent Issue\r\nBcc: attacker@example.com"
	content := "Hello, I found a bug! <script>alert('xss')</script>"

	emailBody, err := BuildFeedbackEmail("customer@example.com", "support@company.com", userName, subject, content)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Println("Generated Email Content:")
	fmt.Println(emailBody)
}

