package main

import (
	"bytes"
	"fmt"
	"html/template"
	"net/smtp"
)

// BuildFeedbackEmail constructs a full email string including SMTP headers and an HTML body.
// The resulting string is formatted to be compatible with net/smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define the email template. 
	// The template includes standard SMTP headers followed by the HTML body.
	const emailTemplate = `From: {{.From}}
To: {{.To}}
Subject: Feedback: {{.Subject}}
MIME-Version: 1.0
Content-Type: text/html; charset="UTF-8"

<!DOCTYPE html>
<html>
<head>
    <style>
        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            line-height: 1.6;
            color: #333;
            margin: 0;
            padding: 20px;
        }
        .container {
            max-width: 600px;
            margin: auto;
            border: 1px solid #e0e0e0;
            border-radius: 8px;
            overflow: hidden;
            box-shadow: 0 2px 5px rgba(0,0,0,0.1);
        }
        .header {
            background-color: #2c3e50;
            color: #ffffff;
            padding: 20px;
            font-size: 20px;
            text-align: center;
        }
        .content {
            padding: 20px;
            background-color: #ffffff;
        }
        .field {
            margin-bottom: 15px;
        }
        .label {
            font-weight: bold;
            color: #7f8c8d;
            display: block;
            margin-bottom: 5px;
            text-transform: uppercase;
            font-size: 12px;
        }
        .value {
            font-size: 16px;
            color: #2c3e50;
        }
        .feedback-box {
            background-color: #f9f9f9;
            border-left: 4px solid #3498db;
            padding: 15px;
            margin-top: 10px;
            white-space: pre-wrap;
            font-style: italic;
        }
        .footer {
            background-color: #f4f4f4;
            text-align: center;
            padding: 10px;
            font-size: 12px;
            color: #95a5a6;
        }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            Customer Support Feedback
        </div>
        <div class="content">
            <div class="field">
                <span class="label">User Name</span>
                <div class="value">{{.UserName}}</div>
            </div>
            <div class="field">
                <span class="label">Subject</span>
                <div class="value">{{.Subject}}</div>
            </div>
            <div class="field">
                <span class="label">Feedback Content</span>
                <div class="feedback-box">{{.FeedbackContent}}</div>
            </div>
        </div>
        <div class="footer">
            This is an automated message generated by the Feedback System.
        </div>
    </div>
</body>
</html>`

	// Parse the template
	t, err := template.New("feedbackEmail").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("error parsing email template: %v", err)
	}

	// Prepare data for the template
	data := struct {
		From            string
		To              string
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		From:            fromAddr,
		To:              toAddr,
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Execute template to a buffer
	var buf bytes.Buffer
	if err := t.Execute(&buf, data); err != nil {
		return "", fmt.Errorf("error executing email template: %v", err)
	}

	// Although we are not sending the email in this function, net/smtp is used 
	// to define the context for which this string is built.
	_ = smtp.PlainAuth("", "", "", "")

	return buf.String(), nil
}

func main() {
	// Example parameters
	from := "web-system@example.com"
	to := "support-team@example.com"
	userName := "John Doe"
	subject := "Issue with Checkout Page"
	content := "Hi Support,\n\nI encountered a 500 error when trying to complete my purchase using a Visa card. Please look into this as soon as possible.\n\nThanks,\nJohn"

	// Build the email
	email, err := BuildFeedbackEmail(from, to, userName, subject, content)
	if err != nil {
		fmt.Printf("Failed to build email: %v\n", err)
		return
	}

	// Output the generated email content
	fmt.Println("--- Generated Email Start ---")
	fmt.Println(email)
	fmt.Println("--- Generated Email End ---")

	fmt.Println("\nNote: This output can be converted to bytes and passed directly to net/smtp.SendMail.")
}

