        .content { padding: 20px; }
        .field { margin-bottom: 15px; }
        .label { font-weight: bold; color: #555; display: block; margin-bottom: 5px; }
        .value { background-color: #f8f9fa; padding: 10px; border-radius: 4px; border: 1px solid #eee; }
        .feedback-text { white-space: pre-wrap; background-color: #fdfdfe; border-left: 4px solid #007bff; }
        .footer { background-color: #f1f1f1; padding: 10px; text-align: center; font-size: 12px; color: #777; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">Customer Feedback Received</div>
        <div class="content">
            <div class="field">
                <span class="label">User Name:</span>
                <div class="value">{{.UserName}}</div>
            </div>
            <div class="field">
                <span class="label">Subject:</span>
                <div class="value">{{.Subject}}</div>
            </div>
            <div class="field">
                <span class="label">Feedback Content:</span>
                <div class="value feedback-text">{{.FeedbackContent}}</div>
            </div>
        </div>
        <div class="footer">
            This is an automated message generated by the Feedback System.
        </div>
    </div>
</body>
</html>`

	// Prepare data for the template
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Parse and execute the template
	tmpl, err := template.New("feedback").Parse(htmlTmpl)
	if err != nil {
		return "", fmt.Errorf("failed to parse template: %v", err)
	}

	var bodyBuffer bytes.Buffer
	if err := tmpl.Execute(&bodyBuffer, data); err != nil {
