package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Basic validation of email addresses
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 2. Prevent Header Injection
	// CRLF characters in headers can allow an attacker to inject additional headers (like Bcc).
	cleanSubject := strings.NewReplacer("\r", "", "\n", "").Replace(subject)

	// 3. MIME Encode the Subject
	// RFC 5322 requires headers to be ASCII. We use Q-encoding to support non-ASCII characters.
	encodedSubject := mime.QEncoding.Encode("utf-8", fmt.Sprintf("Feedback: %s", cleanSubject))

	// 4. Sanitize content for HTML (Prevent XSS)
	// Since the email is HTML-formatted, we must escape user-provided strings 
	// to prevent malicious scripts from executing in the recipient's mail client.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// 5. Construct email headers
	// Note: The double CRLF (\r\n\r\n) separates headers from the body.
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		encodedSubject,
	)

	// 6. Construct HTML body
	// We use pre-wrap for the content to preserve user formatting (newlines) safely.
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body style="font-family: sans-serif; line-height: 1.5; color: #333;">
  <h2 style="color: #2c3e50;">User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div style="margin-top: 20px;">
    <strong>Message:</strong><br>
    <pre style="font-family: inherit; background-color: #f4f4f4; padding: 15px; border-radius: 4px; border: 1px solid #ddd; white-space: pre-wrap; word-break: break-word;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeContent,
	)

	// Combine headers and body
	return headers + htmlBody, nil
}

func main() {
	// Example usage:
	from := "system@example.com"
	to := "support@example.com"
	user := "John Doe"
	sub := "Issue with Login"
	content := "Hello,\nI cannot log in to my account. Please help!"

	email, err := BuildFeedbackEmail(from, to, user, sub, content)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println(email)
}

