package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format and sanitize for headers
	// mail.ParseAddress ensures the address is valid, and .String() returns a 
	// properly formatted/escaped RFC 5322 address string.
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 1. Prevent Email Header Injection:
	// Remove carriage returns and line feeds from the subject to prevent header injection.
	cleanSubject := strings.NewReplacer("\r", "", "\n", "").Replace(subject)

	// Use MIME Q-Encoding to safely handle non-ASCII characters and further 
	// ensure the subject line does not break the header structure.
	encodedSubject := mime.QEncoding.Encode("utf-8", fmt.Sprintf("Feedback: %s", cleanSubject))

	// 2. Prevent XSS: 
	// Escape all user-provided strings before embedding them into the HTML template.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// Construct email headers
	// We use the String() method of the parsed mail.Address to ensure the addresses 
	// are safely formatted for the header block.
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		from.String(),
		to.String(),
		encodedSubject,
	)

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

