import (
	"fmt"
	"html"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
// The returned emailBody includes headers and body, formatted for use with smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Basic validation and parsing of email addresses
	// mail.ParseAddress ensures the addresses are valid and returns a formatted string.
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 2. Sanitize user input for the Email Header
	// To prevent Header Injection, we must ensure the subject does not contain CRLF characters.
	cleanSubject := strings.NewReplacer("\r", "", "\n", "").Replace(subject)
	emailSubject := fmt.Sprintf("Feedback: %s", cleanSubject)

	// 3. Sanitize user input for the HTML Body
	// To prevent HTML Injection (XSS), we must escape all user-provided strings.
	safeUserName := html.EscapeString(userName)
	safeHTMLSubject := html.EscapeString(subject)
	safeFeedbackContent := html.EscapeString(feedbackContent)

	// 4. Construct HTML body with inline styles for better email client compatibility
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
</head>
<body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333;">
  <div style="max-width: 600px; margin: 20px auto; padding: 20px; border: 1px solid #ddd; border-radius: 8px;">
    <h2 style="color: #007bff; border-bottom: 2px solid #007bff; padding-bottom: 10px;">User Feedback Received</h2>
    <p><strong>Submitted by:</strong> %s</p>
    <p><strong>Subject:</strong> %s</p>
    <div style="margin-top: 20px;">
      <strong>Message:</strong>
      <div style="background-color: #f9f9f9; padding: 15px; border: 1px solid #eee; border-left: 4px solid #007bff; margin-top: 10px; white-space: pre-wrap;">%s</div>
    </div>
  </div>
</body>
</html>`,
		safeUserName,
		safeHTMLSubject,
		safeFeedbackContent,
	)

	// 5. Combine headers and body
	// RFC 5322 requires headers and body to be separated by a single blank line (\r\n\r\n).
	// We use the .String() method of mail.Address to ensure proper "Name <email@host.com>" formatting.
	emailMessage := fmt.Sprintf("From: %s\r\n"+
		"To: %s\r\n"+
		"Subject: %s\r\n"+
		"MIME-Version: 1.0\r\n"+
		"Content-Type: text/html; charset=UTF-8\r\n"+
		"\r\n"+
		"%s",
		from.String(),
		to.String(),
		emailSubject,
		htmlBody,
	)

	return emailMessage, nil
}

func main() {
	// Example usage:
	from := "system@example.com"
	to := "support@example.com"
	user := "John Doe"
	subject := "Issue with Login"
	content := "Hi team,\nI am unable to login to my account. It says 'Invalid Credentials'.\n\nBest, John."

	email, err := BuildFeedbackEmail(from, to, user, subject, content)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Generated Email Content:")
	fmt.Println(email)
}

