// BuildFeedbackEmail constructs an HTML-formatted email string including SMTP headers.
// It takes the sender's address, recipient's address, user's name, feedback subject, and content.
// The resulting string is ready to be used with net/smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
	// Define the HTML template for the email body to ensure safe escaping and professional look
	const htmlTmpl = `
<!DOCTYPE html>
<html>
<head>
    <style>
        body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; color: #333; line-height: 1.6; }
        .container { max-width: 600px; margin: 20px auto; border: 1px solid #e0e0e0; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 5px rgba(0,0,0,0.1); }
        .header { background-color: #007bff; color: #ffffff; padding: 20px; text-align: center; }
        .header h2 { margin: 0; font-size: 24px; }
        .content { padding: 30px; background-color: #ffffff; }
        .field { margin-bottom: 20px; }
        .label { font-weight: bold; color: #555; display: block; margin-bottom: 5px; text-transform: uppercase; font-size: 12px; }
        .value { background-color: #f8f9fa; padding: 12px; border-radius: 4px; border-left: 4px solid #007bff; display: block; }
        .feedback-text { white-space: pre-wrap; word-wrap: break-word; }
        .footer { background-color: #f1f3f5; padding: 15px; text-align: center; font-size: 12px; color: #777; border-top: 1px solid #e0e0e0; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>User Feedback Report</h2>
        </div>
        <div class="content">
            <div class="field">
                <span class="label">Submitted By</span>
                <span class="value">{{.UserName}}</span>
            </div>
            <div class="field">
                <span class="label">Subject</span>
                <span class="value">{{.Subject}}</span>
            </div>
            <div class="field">
                <span class="label">Feedback Content</span>
                <div class="value feedback-text">{{.Content}}</div>
            </div>
        </div>
        <div class="footer">
            This email was automatically generated by the User Feedback System.
        </div>
    </div>
</body>
</html>`

	// Parse the template
	tmpl, err := template.New("feedbackEmail").Parse(htmlTmpl)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %v", err)
	}

	// Prepare data for the template
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
	}

	// Execute template to a buffer
	var bodyBuf bytes.Buffer
	if err := tmpl.Execute(&bodyBuf, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %v", err)
	}

	// Build the full email message including RFC 822 headers
	// net/smtp.SendMail requires the message to start with headers
	var builder strings.Builder
	builder.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	builder.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	builder.WriteString(fmt.Sprintf("Subject: %s\r\n", subject))
	builder.WriteString("MIME-Version: 1.0\r\n")
	builder.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	builder.WriteString("\r\n") // Critical blank line between headers and body
	builder.WriteString(bodyBuf.String())

	return builder.String(), nil
}

func main() {
