package main

import (
	"fmt"
	"html"
	"strings"
)

// BuildFeedbackEmail constructs an RFC 822/2822 compliant email string with HTML content.
// This string is ready to be used as the 'msg' parameter in net/smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("sender and recipient addresses must not be empty")
	}

	// 1. Define Headers
	// We manually construct the headers as net/smtp does not provide a high-level builder.
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = fmt.Sprintf("User Feedback: %s", subject)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=\"UTF-8\""

	// 2. Build the Header String
	var headerBuilder strings.Builder
	for key, value := range headers {
		headerBuilder.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}

	// 3. Prepare HTML Content
	// We escape the user input to prevent HTML injection and format newlines for HTML.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := strings.ReplaceAll(html.EscapeString(feedbackContent), "\n", "<br>")

	htmlTemplate := `
<!DOCTYPE html>
<html>
<head>
    <style>
        body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; color: #333; line-height: 1.6; }
        .container { max-width: 600px; margin: 20px auto; border: 1px solid #e0e0e0; border-radius: 10px; overflow: hidden; }
        .header { background-color: #007bff; color: #ffffff; padding: 20px; text-align: center; }
        .content { padding: 30px; }
        .field { margin-bottom: 15px; }
        .label { font-weight: bold; color: #555; display: block; margin-bottom: 5px; }
        .value { background-color: #f8f9fa; padding: 10px; border-radius: 5px; border: 1px solid #eee; }
        .footer { background-color: #f1f1f1; color: #777; padding: 10px; text-align: center; font-size: 12px; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>New Feedback Received</h1>
        </div>
        <div class="content">
            <div class="field">
                <span class="label">User Name:</span>
                <div class="value">%s</div>
            </div>
            <div class="field">
                <span class="label">Subject:</span>
                <div class="value">%s</div>
            </div>
            <div class="field">
                <span class="label">Feedback Content:</span>
                <div class="value">%s</div>
            </div>
        </div>
        <div class="footer">
            This is an automated email generated by the Customer Support System.
        </div>
    </div>
</body>
</html>`

	body := fmt.Sprintf(htmlTemplate, safeUserName, safeSubject, safeContent)

	// 4. Combine Headers and Body
	// RFC 822 requires a blank line (\r\n) between headers and the body.
	emailBody = headerBuilder.String() + "\r\n" + body

	return emailBody, nil
}

func main() {
	// Mock data for demonstration
	from := "no-reply@yourdomain.com"
	to := "support-team@yourdomain.com"
	userName := "Jane Smith"
	subject := "Cannot access dashboard"
	content := "Hi Team,\n\nI've been trying to access the analytics dashboard for the past hour, but it keeps showing a 404 error.\nCould you please look into this?\n\nThanks,\nJane"

	email, err := BuildFeedbackEmail(from, to, userName, subject, content)
	if err != nil {
		fmt.Printf("Failed to build email: %v\n", err)
		return
	}

	// In a real scenario, you would use net/smtp.SendMail as follows:
