package main

import (
	"bytes"
	"fmt"
	"html/template"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
//
// This function addresses security concerns by:
// 1. Validating email addresses using net/mail.
// 2. Sanitizing the Subject header to prevent header injection (CRLF injection).
// 3. Using html/template to automatically escape user-provided content,
//    preventing HTML injection (XSS) in the email body.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// 2. Validate email addresses format
	// This ensures the addresses are valid and do not contain malicious control characters
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 3. Sanitize subject to prevent header injection
	// We remove any Carriage Return (\r) or Line Feed (\n) characters
	cleanSubject := strings.NewReplacer("\r", "", "\n", "").Replace(subject)
	emailSubject := fmt.Sprintf("Feedback: %s", cleanSubject)

	// 4. Define HTML template for the body
	// html/template provides context-aware escaping for safe HTML generation
	const htmlTmpl = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body style="font-family: sans-serif; line-height: 1.5; color: #333;">
  <h2 style="border-bottom: 2px solid #eee; padding-bottom: 10px;">User Feedback Received</h2>
  <p><strong>Submitted by:</strong> {{.UserName}}</p>
  <p><strong>Subject:</strong> {{.Subject}}</p>
  <div style="margin-top: 20px;">
    <strong>Message:</strong><br>
    <div style="background-color: #f9f9f9; padding: 15px; border: 1px solid #ddd; border-radius: 4px; white-space: pre-wrap; margin-top: 10px; font-family: inherit;">{{.Content}}</div>
  </div>
</body>
</html>`

	tmpl, err := template.New("feedback").Parse(htmlTmpl)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Prepare template data
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
	}

	// Execute template to a buffer
	var bodyBuf bytes.Buffer
	if err := tmpl.Execute(&bodyBuf, data); err != nil {
		return "", fmt.Errorf("failed to generate HTML content: %w", err)
	}

	// 5. Construct RFC 5322 email headers
	// We use \r\n as the line separator as required by the SMTP protocol
	// MIME-Version and Content-Type tell the email client to render the body as HTML
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// 6. Combine headers and body
	// The resulting string is ready to be cast to []byte and sent via net/smtp.SendMail
	return headers + bodyBuf.String(), nil
}

func main() {
	// Example usage:
	from := "web-form@example.com"
	to := "support-team@example.com"
	userName := "Jane Doe"
	subject := "Cannot access dashboard"
	content := "Hi,\nI've been trying to log in but the dashboard keeps spinning. <script>alert('test')</script>"

	email, err := BuildFeedbackEmail(from, to, userName, subject, content)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Println("Generated Email Content:")
	fmt.Println("-------------------------")
	fmt.Println(email)
	fmt.Println("-------------------------")
	fmt.Println("The output above is now safe and ready to be sent via smtp.SendMail.")
}

