func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
	// Define the HTML template for the email body
	// We use html/template to ensure user input is properly escaped for security
	const emailTmpl = `From: {{.From}}
To: {{.To}}
Subject: {{.Subject}}
MIME-Version: 1.0
Content-Type: text/html; charset="UTF-8"

<!DOCTYPE html>
<html>
<head>
    <style>
        body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; color: #333; line-height: 1.6; }
        .container { max-width: 600px; margin: 20px auto; border: 1px solid #e0e0e0; border-radius: 8px; overflow: hidden; }
        .header { background-color: #007bff; color: #ffffff; padding: 20px; font-size: 20px; font-weight: bold; }
        .content { padding: 20px; }
        .info-row { margin-bottom: 15px; }
        .label { font-weight: bold; color: #555; display: block; margin-bottom: 5px; }
        .value { background-color: #f8f9fa; padding: 10px; border-radius: 4px; border-left: 4px solid #007bff; }
        .footer { background-color: #f1f1f1; padding: 10px; text-align: center; font-size: 12px; color: #777; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">Customer Feedback Received</div>
        <div class="content">
            <div class="info-row">
                <span class="label">User Name:</span>
                <div class="value">{{.UserName}}</div>
            </div>
            <div class="info-row">
                <span class="label">Subject:</span>
                <div class="value">{{.FeedbackSubject}}</div>
            </div>
            <div class="info-row">
                <span class="label">Feedback Content:</span>
                <div class="value" style="white-space: pre-wrap;">{{.FeedbackContent}}</div>
            </div>
        </div>
        <div class="footer">
            This is an automated message generated by the Feedback System.
        </div>
    </div>
</body>
</html>`

	// Data structure for template execution
	data := struct {
		From            string
		To              string
		Subject         string
		UserName        string
		FeedbackSubject string
		FeedbackContent string
	}{
		From:            fromAddr,
		To:              toAddr,
		Subject:         "New Feedback: " + subject,
		UserName:        userName,
		FeedbackSubject: subject,
		FeedbackContent: feedbackContent,
	}

	// Parse and execute the template
