package main

import (
	"fmt"
	"html"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
	// 1. Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 2. Sanitize Subject for Headers (Prevent Header Injection)
	// We must remove carriage returns and line feeds to prevent attackers from 
	// injecting additional headers into the email.
	cleanSubject := strings.NewReplacer("\r", "", "\n", "").Replace(subject)
	emailSubject := fmt.Sprintf("Feedback: %s", cleanSubject)

	// 3. Escape content for HTML Body (Prevent XSS)
	// User-provided strings must be escaped so they cannot execute scripts in the recipient's mail client.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// 4. Construct email headers
	// RFC 5322 requires CRLF (\r\n) line endings for headers.
	var header strings.Builder
	header.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	header.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	header.WriteString(fmt.Sprintf("Subject: %s\r\n", emailSubject))
	header.WriteString("MIME-Version: 1.0\r\n")
	header.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	header.WriteString("\r\n") // End of headers

	// 5. Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
</head>
<body style="font-family: sans-serif; line-height: 1.6; color: #333;">
  <div style="max-width: 600px; margin: auto; border: 1px solid #eee; padding: 20px;">
    <h2 style="color: #2c3e50; border-bottom: 1px solid #eee; padding-bottom: 10px;">User Feedback Received</h2>
    <p><strong>Submitted by:</strong> %s</p>
    <p><strong>Subject:</strong> %s</p>
    <div style="margin-top: 20px;">
      <strong>Message:</strong><br>
      <div style="background-color: #f9f9f9; padding: 15px; border-radius: 5px; white-space: pre-wrap; margin-top: 10px; border: 1px solid #ddd;">%s</div>
    </div>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeContent,
	)

	// Combine headers and body
	return header.String() + htmlBody, nil
}

func main() {
	// Example usage
	from := "sender@example.com"
	to := "support@example.com"
	user := "John Doe"
	sub := "Issue with Login"
	content := "I cannot log in to my account. It says \"Invalid Credentials\" even though they are correct."

	email, err := BuildFeedbackEmail(from, to, user, sub, content)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Generated Email Content:")
	fmt.Println("-------------------------")
	fmt.Print(email)
}

