// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// 2. Validate and format email addresses to prevent header injection via address fields.
	// mail.ParseAddress ensures the address is valid, and Address.String() 
	// ensures it is correctly quoted/formatted for the RFC 5322 header.
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 3. Sanitize Subject to prevent Header Injection (CRLF injection).
	// We remove \r and \n to ensure the subject line doesn't terminate early 
	// or allow an attacker to inject additional headers (like Bcc).
	cleanSubject := strings.NewReplacer("\r", "", "\n", "").Replace(subject)
	emailSubject := fmt.Sprintf("Feedback: %s", cleanSubject)

	// 4. Escape content for HTML to prevent Cross-Site Scripting (XSS).
	// Since the email body is HTML, user-provided content must be escaped so 
	// it cannot execute malicious scripts in the support staff's email client.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeFeedbackContent := html.EscapeString(feedbackContent)

	// 5. Construct Email Message (Headers + Body)
	// We use a bytes.Buffer for efficient string construction.
	var buf bytes.Buffer

	// Write Headers
	buf.WriteString(fmt.Sprintf("From: %s\r\n", from.String()))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", to.String()))
	buf.WriteString(fmt.Sprintf("Subject: %s\r\n", emailSubject))
	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	buf.WriteString("\r\n") // CRLF separator between headers and body

	// Write HTML Body
	htmlTemplate := `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`

	buf.WriteString(fmt.Sprintf(htmlTemplate,
		safeUserName,
		safeSubject,
		safeFeedbackContent,
	))

	return buf.String(), nil
}

