// It includes the necessary headers and a formatted HTML body containing user feedback.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define the HTML template for the email body
	const emailTemplate = `
<!DOCTYPE html>
<html>
<head>
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        .container { width: 80%; margin: 20px auto; border: 1px solid #ddd; padding: 20px; border-radius: 8px; }
        .header { font-size: 18px; font-weight: bold; border-bottom: 2px solid #0056b3; padding-bottom: 10px; margin-bottom: 20px; }
        .field { margin-bottom: 10px; }
        .label { font-weight: bold; color: #555; }
        .content-box { background: #f9f9f9; border: 1px solid #eee; padding: 15px; margin-top: 10px; white-space: pre-wrap; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">New User Feedback Received</div>
        <div class="field"><span class="label">From User:</span> {{.UserName}}</div>
        <div class="field"><span class="label">Subject:</span> {{.Subject}}</div>
        <div class="field"><span class="label">Feedback Content:</span></div>
        <div class="content-box">{{.Content}}</div>
    </div>
</body>
</html>`

	// Prepare data for the template
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
	}

	// Parse and execute the template
	tmpl, err := template.New("feedback").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse template: %v", err)
	}

	var bodyBuffer bytes.Buffer
	if err := tmpl.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute template: %v", err)
	}

	// Construct SMTP headers
	// net/smtp SendMail expects the full raw message including headers
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = fmt.Sprintf("Feedback: %s", subject)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=\"UTF-8\""

	var messageBuilder strings.Builder
	for key, value := range headers {
		messageBuilder.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}
	messageBuilder.WriteString("\r\n") // Blank line between headers and body
	messageBuilder.WriteString(bodyBuffer.String())

	return messageBuilder.String(), nil
}

