// BuildFeedbackEmail constructs an HTML-formatted email body including headers
// suitable for use with net/smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define email headers
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = fmt.Sprintf("User Feedback: %s", subject)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=\"UTF-8\""

	// Build the header string
	var headerBuilder strings.Builder
	for key, value := range headers {
		headerBuilder.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}
	headerBuilder.WriteString("\r\n") // End of headers

	// Build the HTML body
	// We use basic CSS styling for a professional look in email clients
	htmlTemplate := `
<!DOCTYPE html>
<html>
<head>
    <style>
        body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; line-height: 1.6; color: #333; }
        .container { max-width: 600px; margin: 20px auto; border: 1px solid #e0e0e0; border-radius: 8px; overflow: hidden; }
        .header { background-color: #007bff; color: #ffffff; padding: 20px; font-size: 20px; font-weight: bold; }
        .content { padding: 20px; background-color: #ffffff; }
        .field { margin-bottom: 15px; }
        .label { font-weight: bold; color: #555; display: block; margin-bottom: 5px; }
        .value { color: #000; padding: 10px; background-color: #f8f9fa; border-radius: 4px; }
        .footer { background-color: #f1f1f1; color: #777; padding: 10px; text-align: center; font-size: 12px; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">New Feedback Received</div>
        <div class="content">
            <div class="field">
                <span class="label">User Name:</span>
                <div class="value">%s</div>
            </div>
            <div class="field">
                <span class="label">Subject:</span>
                <div class="value">%s</div>
            </div>
            <div class="field">
                <span class="label">Feedback Content:</span>
                <div class="value" style="white-space: pre-wrap;">%s</div>
            </div>
        </div>
        <div class="footer">
            This is an automated message from the Customer Feedback System.
        </div>
    </div>
</body>
</html>`

	body := fmt.Sprintf(htmlTemplate, userName, subject, feedbackContent)

	// Combine headers and body
	emailBody = headerBuilder.String() + body

	return emailBody, nil
}

