	headers["To"] = toAddr
	headers["Subject"] = "Customer Feedback: " + safeSubject
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=\"UTF-8\""

	// Construct the raw email string
	var builder strings.Builder

	// Write headers with CRLF line endings as per SMTP spec (RFC 5322)
	for key, value := range headers {
		builder.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}
	builder.WriteString("\r\n") // Empty line separating headers from body

	// Construct the HTML body
